 1	import React, { FC } from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	import { useLocation } from 'react-router-dom-v5-compat';
 4	
 5	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { getVMStatus } from '@kubevirt-utils/resources/shared';
 8	import { Popover, PopoverPosition, Progress, ProgressSize, Text } from '@patternfly/react-core';
 9	import { createURL } from '@virtualmachines/details/tabs/overview/utils/utils';
10	
11	import useProvisioningPercentage from '../../../../../../../../../utils/resources/vm/hooks/useProvisioningPercentage';
12	
13	import './virtualmachine-provisioning-status.scss';
14	
15	type VirtualMachineProvisioningStatusProps = {
16	  vm: V1VirtualMachine;
17	};
18	
19	const VirtualMachineProvisioningStatus: FC<VirtualMachineProvisioningStatusProps> = ({
20	  children,
21	  vm,
22	}) => {
23	  const vmPrintableStatus = getVMStatus(vm);
24	
25	  const { t } = useKubevirtTranslation();
26	  const { percentages } = useProvisioningPercentage(vm);
27	
28	  const numberOfProvisioningDisks = Object.keys(percentages).length;
29	
30	  const location = useLocation();
31	
32	  return (
33	    <Popover
34	      bodyContent={
35	        <>
36	          <Text>{t('VirtualMachine is currently provisioning')}</Text>
37	          <br />
38	
39	          {Object.keys(percentages).map((diskName) => (
40	            <Progress
41	              className="progress"
42	              key={diskName}
43	              size={ProgressSize.lg}
44	              title={numberOfProvisioningDisks > 1 ? diskName : t('Copying files')}
45	              value={parseFloat(percentages[diskName])}
46	            />
47	          ))}
48	          <br />
49	          <Text>
50	            <Link to={createURL('diagnostics', location?.pathname)}>{t('View diagnostic')}</Link>
51	          </Text>
52	        </>
53	      }
54	      className="virtualmachine-privisioning-status"
55	      headerContent={vmPrintableStatus}
56	      position={PopoverPosition.right}
57	    >
58	      <>{children}</>
59	    </Popover>
60	  );
61	};
62	
63	export default VirtualMachineProvisioningStatus;

